module RefModule(
  input clk,
  input reset,
  input load_data,
  input [31:0] in_data,
  output reg [31:0] shift_out,
  output reg [31:0] parallel_out
);reg [31:0] obf_register;

  always @(posedge clk) begin
    if (reset) begin
      obf_register <= 32'b0;
    end else if (load_data) begin
      obf_register <= in_data;
    end else begin
      obf_register <= {obf_register[30:0], obf_register[31]};
    end
  end

  assign shift_out = obf_register;
  assign parallel_out = load_data ? in_data : obf_register;

endmodule
